sql:
SELECT title, genre_name, rating
FROM movies
JOIN genres ON movies.genre_id = genres.genre_id;

SELECT m.title, g.genre_name, m.rating
FROM movies m
JOIN genres g ON m.genre_id = g.genre_id;

external_knowledge:
- "cinematic gems" refers to highly rated movies;
- "pinnacle of critical acclaim" signifies the top ratings achieved;
- "shining stars among the ratings" metaphorically refers to the average rating, highlighting movies with the highest average ratings.

- 'cinematic journey' refers to the runtime of a movie; 
- 'embarked' is a metaphor for movie release; 
- 'dawn of the new millennium' refers to the year 2000; 
- 'end of the first decade' refers to the year 2010.

sql:
SELECT AVG(runtime) AS average_runtime
FROM movies
WHERE released_date BETWEEN '2000-01-01' AND '2010-12-31';
